    //    so existing documents remain accessible via FindAsync/point-reads.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // 3. HasIndex now throws for Cosmos entities â€” removed.
    //    Cosmos DB indexing is managed via the container's indexing policy.
}

